import{_ as a,c as t,d as e,o}from"./index-BKW5s1dQ.js";const s={},r={class:"doc-page"};function n(i,d){return o(),t("div",r,[...d[0]||(d[0]=[e(`<h1 data-v-d4fad165>Documentation</h1><p class="doc-intro" data-v-d4fad165> Complete reference for CloudRadar — from first-time setup to running every scan, report, and test. Use the table of contents to jump to a section. </p><nav class="doc-toc" data-v-d4fad165><a href="#getting-started" data-v-d4fad165>Getting started</a><a href="#cloud-selection" data-v-d4fad165>Cloud selection</a><a href="#setup" data-v-d4fad165>Setup &amp; credentials</a><a href="#security" data-v-d4fad165>Security — Full scan</a><a href="#vulnerabilities" data-v-d4fad165>Security — Vulnerabilities</a><a href="#audit" data-v-d4fad165>Audit</a><a href="#compliance" data-v-d4fad165>Compliance</a><a href="#governance" data-v-d4fad165>Governance</a><a href="#pentest" data-v-d4fad165>Pentest</a><a href="#tests" data-v-d4fad165>Tests</a><a href="#hosting" data-v-d4fad165>Running locally &amp; on a server</a></nav><section class="doc-section" id="getting-started" data-v-d4fad165><h2 data-v-d4fad165>Getting started</h2><p data-v-d4fad165><strong data-v-d4fad165>CloudRadar</strong> is a multi-cloud Security &amp; Cloud Security Posture Management (CSPM) tool. It discovers resources in AWS, Google Cloud, and Azure; runs security rules and compliance checks; and produces findings, reports, and pentest output — all from a browser UI. </p><p data-v-d4fad165> Click the <strong data-v-d4fad165>CloudRadar logo</strong> in the top-left of the sidebar at any time to return to the cloud-selection screen. </p><p data-v-d4fad165> Every run button supports <strong data-v-d4fad165>script selection</strong>: expand the checklist above the run button, tick or untick individual scripts, and click <strong data-v-d4fad165>All / None</strong> to quickly change the selection. Only the ticked scripts will execute — giving you full control over what runs. </p></section><section class="doc-section" id="cloud-selection" data-v-d4fad165><h2 data-v-d4fad165>Cloud selection</h2><p data-v-d4fad165> The first screen shows three cloud provider cards: <strong data-v-d4fad165>AWS</strong>, <strong data-v-d4fad165>Google Cloud</strong>, and <strong data-v-d4fad165>Azure</strong>. Click the one that matches your environment. You are taken to the Setup page for that provider. You can change provider at any time from the sidebar Setup page. </p></section><section class="doc-section" id="setup" data-v-d4fad165><h2 data-v-d4fad165>Setup &amp; credentials</h2><p data-v-d4fad165>Credentials are stored in <code data-v-d4fad165>config.yaml</code> in the project root. Restrict file permissions and never commit this file.</p><table class="doc-table" data-v-d4fad165><thead data-v-d4fad165><tr data-v-d4fad165><th data-v-d4fad165>Cloud</th><th data-v-d4fad165>Required fields</th><th data-v-d4fad165>Notes</th></tr></thead><tbody data-v-d4fad165><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>AWS</strong></td><td data-v-d4fad165>Region, Access Key ID, Secret Access Key</td><td data-v-d4fad165>Session Token optional (for temporary credentials). Or use an IAM role / AWS profile instead of keys.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>GCP</strong></td><td data-v-d4fad165>Project ID</td><td data-v-d4fad165>Service account JSON path optional — leave blank to use <code data-v-d4fad165>gcloud auth application-default login</code>.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Azure</strong></td><td data-v-d4fad165>Subscription ID, Tenant ID, Client ID, Client secret</td><td data-v-d4fad165>Create a service principal with Reader + Security Reader roles on the subscription.</td></tr></tbody></table><p data-v-d4fad165> Click <strong data-v-d4fad165>Save and continue</strong> to persist credentials and open the Dashboard, or <strong data-v-d4fad165>Setup later</strong> to skip and configure via environment variables or cloud instance roles. </p></section><section class="doc-section" id="security" data-v-d4fad165><h2 data-v-d4fad165>Security — Full security scan</h2><p data-v-d4fad165> The <strong data-v-d4fad165>Security Scan</strong> runs end-to-end discovery, enrichment, rule evaluation, risk scoring, and optionally saves a snapshot. Progress is shown step-by-step in real time. Reports can be downloaded as JSON or HTML. </p><p data-v-d4fad165> You can choose <strong data-v-d4fad165>which services to scan</strong> using the script selector — deselect any service to skip it completely (faster scans, lower API call cost). </p><h3 data-v-d4fad165>Services &amp; what is checked</h3><table class="doc-table" data-v-d4fad165><thead data-v-d4fad165><tr data-v-d4fad165><th data-v-d4fad165>Service</th><th data-v-d4fad165>Script ID</th><th data-v-d4fad165>What is checked</th></tr></thead><tbody data-v-d4fad165><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>EC2</strong></td><td data-v-d4fad165><code data-v-d4fad165>ec2</code></td><td data-v-d4fad165>Public IPs on instances, vulnerable AMIs, instance types, missing required tags.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>S3</strong></td><td data-v-d4fad165><code data-v-d4fad165>s3</code></td><td data-v-d4fad165>Public-access-block disabled, missing server-side encryption, overly permissive bucket policies.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>RDS</strong></td><td data-v-d4fad165><code data-v-d4fad165>rds</code></td><td data-v-d4fad165>Publicly accessible flag, storage encryption at rest disabled.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Lambda</strong></td><td data-v-d4fad165><code data-v-d4fad165>lambda</code></td><td data-v-d4fad165>Short or missing timeout, hardcoded secrets in env vars, missing tags.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>IAM</strong></td><td data-v-d4fad165><code data-v-d4fad165>iam</code></td><td data-v-d4fad165>Wildcard actions in policies, admin-policy attachments to users/roles, unused access keys.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Security Groups</strong></td><td data-v-d4fad165><code data-v-d4fad165>sg</code></td><td data-v-d4fad165>Inbound rules open to 0.0.0.0/0 on ports 22 (SSH), 3389 (RDP), 3306, 5432, 1433, and others.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>ALB / Load Balancers</strong></td><td data-v-d4fad165><code data-v-d4fad165>alb</code></td><td data-v-d4fad165>Internet-facing ALBs missing WAF Web ACL, access logging disabled.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>WAF</strong></td><td data-v-d4fad165><code data-v-d4fad165>waf</code></td><td data-v-d4fad165>Web ACLs not associated with API Gateway or ALB resources.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>CloudTrail</strong></td><td data-v-d4fad165><code data-v-d4fad165>cloudtrail</code></td><td data-v-d4fad165>Multi-region not enabled, log file validation off, CloudWatch Logs integration missing.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>VPC</strong></td><td data-v-d4fad165><code data-v-d4fad165>vpc</code></td><td data-v-d4fad165>Default VPC still in use, VPC flow logs not enabled.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>EBS Volumes</strong></td><td data-v-d4fad165><code data-v-d4fad165>ebs</code></td><td data-v-d4fad165>Volumes without encryption at rest.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>EKS</strong></td><td data-v-d4fad165><code data-v-d4fad165>eks</code></td><td data-v-d4fad165>Public API server endpoint, control plane logging disabled, secrets encryption missing.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>ECS</strong></td><td data-v-d4fad165><code data-v-d4fad165>ecs</code></td><td data-v-d4fad165>Privileged containers, missing CloudWatch log config, containers running as root.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>KMS</strong></td><td data-v-d4fad165><code data-v-d4fad165>kms</code></td><td data-v-d4fad165>Customer-managed keys with automatic rotation disabled.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>API Gateway</strong></td><td data-v-d4fad165><code data-v-d4fad165>apigateway</code></td><td data-v-d4fad165>Access logging not enabled, WAF not attached to REST API stages.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>SQS</strong></td><td data-v-d4fad165><code data-v-d4fad165>sqs</code></td><td data-v-d4fad165>Queues without server-side encryption, public resource policy exposure.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>DynamoDB</strong></td><td data-v-d4fad165><code data-v-d4fad165>dynamodb</code></td><td data-v-d4fad165>Tables without encryption at rest, point-in-time recovery (PITR) disabled.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>GuardDuty</strong></td><td data-v-d4fad165><code data-v-d4fad165>guardduty</code></td><td data-v-d4fad165>Threat detection detector not enabled in the scanned region.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>CloudWatch</strong></td><td data-v-d4fad165><code data-v-d4fad165>cloudwatch</code></td><td data-v-d4fad165>Missing CIS metric filters for root login, IAM/CloudTrail/VPC/KMS/S3 changes.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>ECR</strong></td><td data-v-d4fad165><code data-v-d4fad165>ecr</code></td><td data-v-d4fad165>Container images with critical/high CVEs, scan-on-push not enabled.</td></tr></tbody></table><h3 data-v-d4fad165>How to use script selection</h3><ol data-v-d4fad165><li data-v-d4fad165>On the <strong data-v-d4fad165>Security Scan</strong> page, all 20 services are pre-selected.</li><li data-v-d4fad165>Click <strong data-v-d4fad165>None</strong> then tick only the services you care about — or click <strong data-v-d4fad165>All</strong> to reset.</li><li data-v-d4fad165>Individual services can be toggled by clicking their row.</li><li data-v-d4fad165>The run button shows how many services are selected. The scan will only call AWS APIs for those services.</li></ol></section><section class="doc-section" id="vulnerabilities" data-v-d4fad165><h2 data-v-d4fad165>Security — Vulnerabilities</h2><p data-v-d4fad165> A focused scan for known CVEs and AMI issues — without running the full CSPM rule engine. Useful for a quick container security check after a deployment. </p><table class="doc-table" data-v-d4fad165><thead data-v-d4fad165><tr data-v-d4fad165><th data-v-d4fad165>Script</th><th data-v-d4fad165>ID</th><th data-v-d4fad165>What it does</th></tr></thead><tbody data-v-d4fad165><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>ECR Image Scan</strong></td><td data-v-d4fad165><code data-v-d4fad165>ecr</code></td><td data-v-d4fad165>Pulls all ECR repositories and checks each image tag for CVE findings reported by AWS ECR native scanning or Inspector. Reports critical and high severity CVEs with package name, version, and fix version where available.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>AMI Vulnerability Check</strong></td><td data-v-d4fad165><code data-v-d4fad165>ami</code></td><td data-v-d4fad165>Checks EC2 instances for deprecated AMIs (older than 180 days), public AMI usage, and AMI IDs on known-vulnerable lists. Flags instances that should be re-imaged.</td></tr></tbody></table></section><section class="doc-section" id="audit" data-v-d4fad165><h2 data-v-d4fad165>Audit</h2><p data-v-d4fad165>Audit scripts let you inspect and compare your asset catalog over time. They do not run security rules.</p><table class="doc-table" data-v-d4fad165><thead data-v-d4fad165><tr data-v-d4fad165><th data-v-d4fad165>Script</th><th data-v-d4fad165>What it does</th><th data-v-d4fad165>Options</th></tr></thead><tbody data-v-d4fad165><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>List assets</strong></td><td data-v-d4fad165>Exports the full asset catalog from the last scan (or a named snapshot) as JSON or CSV. Includes resource type, ID, region, tags, and a risk-score field.</td><td data-v-d4fad165>Output format (JSON / CSV); Snapshot ID (optional — leave blank for latest scan).</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Changes</strong></td><td data-v-d4fad165>Compares the current cloud state with the last saved snapshot. Reports new resources (added), removed resources (deleted), and modified resources (config diff). Useful for change-control audits.</td><td data-v-d4fad165>Runs automatically from latest scan vs. previous snapshot.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Snapshot diff</strong></td><td data-v-d4fad165>Compares two named snapshots by ID. Shows the exact diff between any two points in time — good for reviewing what changed between a deployment and a rollback.</td><td data-v-d4fad165>Snapshot ID A and Snapshot ID B.</td></tr></tbody></table></section><section class="doc-section" id="compliance" data-v-d4fad165><h2 data-v-d4fad165>Compliance</h2><p data-v-d4fad165> Maps security findings to framework controls and generates a pass/fail report. The compliance check uses findings from the latest scan (or triggers a scan first if no data exists). Output can be JSON or HTML. </p><table class="doc-table" data-v-d4fad165><thead data-v-d4fad165><tr data-v-d4fad165><th data-v-d4fad165>Framework</th><th data-v-d4fad165>Standard</th><th data-v-d4fad165>Focus &amp; controls checked</th></tr></thead><tbody data-v-d4fad165><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>CIS</strong></td><td data-v-d4fad165>CIS AWS Foundations Benchmark v1.5</td><td data-v-d4fad165>AWS-specific hardening: IAM password policy, MFA on root, CloudTrail enabled, VPC flow logs, S3 logging, CloudWatch alarms for key events.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>SOC 2</strong></td><td data-v-d4fad165>AICPA SOC 2 Trust Services Criteria</td><td data-v-d4fad165>Logical access controls, encryption in transit and at rest, monitoring, incident response readiness, availability of key services.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>HIPAA</strong></td><td data-v-d4fad165>HIPAA Security Rule (45 CFR Part 164)</td><td data-v-d4fad165>Access control (§164.312(a)), audit controls (§164.312(b)), integrity (§164.312(c)), transmission security (§164.312(e)), encryption of PHI at rest and in transit.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>PCI DSS</strong></td><td data-v-d4fad165>PCI DSS v4.0</td><td data-v-d4fad165>Firewall rules (Req. 1), no default credentials (Req. 2), encryption of cardholder data (Req. 3–4), access control (Req. 7–8), monitoring &amp; logging (Req. 10).</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>ISO 27001</strong></td><td data-v-d4fad165>ISO/IEC 27001:2022 Annex A</td><td data-v-d4fad165>A.5 policies, A.6 people controls, A.8 asset management, A.8.20 network security, A.8.24 cryptography, A.8.15 logging, A.5.33 data protection, A.8.16 monitoring.</td></tr></tbody></table></section><section class="doc-section" id="governance" data-v-d4fad165><h2 data-v-d4fad165>Governance</h2><p data-v-d4fad165> Governance checks enforce your organisation&#39;s resource policies and tagging standards. Select only the checks relevant to your environment. Output as JSON or HTML. </p><table class="doc-table" data-v-d4fad165><thead data-v-d4fad165><tr data-v-d4fad165><th data-v-d4fad165>Script</th><th data-v-d4fad165>ID</th><th data-v-d4fad165>What it does</th></tr></thead><tbody data-v-d4fad165><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Tag Compliance</strong></td><td data-v-d4fad165><code data-v-d4fad165>tags</code></td><td data-v-d4fad165>Scans all resources for required tags (e.g. <code data-v-d4fad165>Environment</code>, <code data-v-d4fad165>Owner</code>, <code data-v-d4fad165>CostCenter</code>). Reports resources with missing, empty, or non-standard tag values. Tag requirements are configurable in <code data-v-d4fad165>config.yaml</code>.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Resource Policy Checks</strong></td><td data-v-d4fad165><code data-v-d4fad165>policy</code></td><td data-v-d4fad165>Validates resources against defined policies: forbidden instance types in production environments, minimum backup retention periods, required encryption settings. Policy rules are defined in <code data-v-d4fad165>config.yaml</code>.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Policy Violations</strong></td><td data-v-d4fad165><code data-v-d4fad165>violations</code></td><td data-v-d4fad165>Detects resources that violate governance policies derived from security findings: publicly exposed resources, unencrypted storage volumes, over-privileged IAM roles (e.g. Administrator access attached to users).</td></tr></tbody></table></section><section class="doc-section" id="pentest" data-v-d4fad165><h2 data-v-d4fad165>Pentest</h2><p data-v-d4fad165> Pentest checks simulate an attacker&#39;s perspective — finding exposed entry points, leaked secrets, and exploitable chains. Results augment the full security scan with attacker-centric context. Select only the checks you want. </p><table class="doc-table" data-v-d4fad165><thead data-v-d4fad165><tr data-v-d4fad165><th data-v-d4fad165>Script</th><th data-v-d4fad165>ID</th><th data-v-d4fad165>What it does</th></tr></thead><tbody data-v-d4fad165><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Exposed Services</strong></td><td data-v-d4fad165><code data-v-d4fad165>exposed</code></td><td data-v-d4fad165>Checks all security groups and network ACLs for inbound rules that expose sensitive ports to the public internet (0.0.0.0/0 or ::/0): SSH (22), RDP (3389), MySQL (3306), PostgreSQL (5432), MSSQL (1433), MongoDB (27017), Redis (6379), Elasticsearch (9200), and others.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Secrets Scan</strong></td><td data-v-d4fad165><code data-v-d4fad165>secrets</code></td><td data-v-d4fad165>Searches asset metadata (Lambda environment variables, EC2 user-data, ECS task definitions) and optionally a supplied local repository path for hardcoded secrets: AWS keys, API tokens, passwords, RSA private keys, and common secret patterns using regex matching.</td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Exploit Mapping</strong></td><td data-v-d4fad165><code data-v-d4fad165>exploits</code></td><td data-v-d4fad165>Takes the current findings and maps them to known exploit scenarios using a graph-based attack path engine (built on networkx). Example chains: public-S3 + wildcard-IAM = data exfiltration; public-RDS + no-encryption = SQL injection + data exposure; exposed-EC2 + EKS-public-API = cluster takeover path.</td></tr></tbody></table></section><section class="doc-section" id="tests" data-v-d4fad165><h2 data-v-d4fad165>Tests</h2><p data-v-d4fad165> The <strong data-v-d4fad165>Tests</strong> tab runs CloudRadar&#39;s built-in unit and integration test suite using <code data-v-d4fad165>pytest</code>. Tests are completely <strong data-v-d4fad165>isolated from cloud scans</strong> — they use mocked AWS services (<code data-v-d4fad165>moto</code>) and never make real API calls. Run tests to validate that your local installation is working correctly or after making custom rule changes. </p><p data-v-d4fad165> Select any combination of test modules from the checklist, then click <strong data-v-d4fad165>Run Tests</strong>. Output streams in real time. Each test is shown as passed (✓), failed (✗), error (⚠), or skipped (–). A summary banner shows the final result. </p><h3 data-v-d4fad165>Test modules</h3><table class="doc-table" data-v-d4fad165><thead data-v-d4fad165><tr data-v-d4fad165><th data-v-d4fad165>Module</th><th data-v-d4fad165>What it tests</th></tr></thead><tbody data-v-d4fad165><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Rule Engine</strong></td><td data-v-d4fad165> Validates that security rules fire correctly and produce accurate findings. Covers: S3 public-access-block disabled → CRITICAL finding; RDS publicly accessible → HIGH; EC2 missing encryption → MEDIUM; IAM wildcard action → HIGH; missing tags → LOW. Also checks that finding fields (rule_id, severity, resource_id, description) are always populated. </td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>S3 Scanner</strong></td><td data-v-d4fad165> Tests the S3-specific scanner module end-to-end (mocked with moto). Checks: public-access-block disabled is detected; encryption not set raises finding; permissive bucket policy (s3:GetObject for *) is flagged; clean bucket produces zero findings. </td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Compliance Frameworks</strong></td><td data-v-d4fad165> Verifies all five compliance frameworks (CIS, SOC 2, HIPAA, PCI DSS, ISO 27001). For each framework: finds are correctly mapped to controls; pass/fail status per control is accurate; report structure contains required fields (framework, controls, summary); a clean environment with no findings produces an all-pass report. </td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Remediation Engine</strong></td><td data-v-d4fad165> Checks that the remediation module generates correct auto-remediation actions for each finding type. Examples tested: S3 public-access-block → enable-public-access-block action generated; EBS unencrypted → create-encrypted-copy action; RDS publicly accessible → modify-db-instance action. Validates action schema (action_type, resource_id, parameters). </td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>Attack Paths</strong></td><td data-v-d4fad165> Tests the attack path graph engine. Validates that the graph is built correctly from findings, that a public-EC2 → open-security-group → sensitive-RDS chain is detected and scores above the HIGH threshold, and that an isolated resource with no exposure produces no attack path. </td></tr><tr data-v-d4fad165><td data-v-d4fad165><strong data-v-d4fad165>All Scanners</strong></td><td data-v-d4fad165> Integration tests for every scanner module using mocked AWS services. Covers: EC2, RDS, IAM, Lambda, CloudTrail, VPC, EBS, EKS, ECS, KMS, API Gateway, SQS, DynamoDB, GuardDuty, and CloudWatch. Each test creates a deliberately misconfigured mocked resource, runs the scanner, and asserts the expected finding is raised with the correct severity. </td></tr></tbody></table><h3 data-v-d4fad165>How tests work</h3><ul data-v-d4fad165><li data-v-d4fad165>Tests are run in a <strong data-v-d4fad165>separate subprocess</strong> — completely isolated from the web server and any ongoing scan.</li><li data-v-d4fad165>AWS calls are intercepted by <code data-v-d4fad165>moto</code> — no real AWS credentials are needed.</li><li data-v-d4fad165>Tests only start when you click <strong data-v-d4fad165>Run Tests</strong> from the Tests page.</li><li data-v-d4fad165>You can select a subset (e.g. only run Compliance tests after updating a compliance rule).</li><li data-v-d4fad165>Output streams line-by-line in real time via Server-Sent Events with a polling fallback.</li></ul></section><section class="doc-section" id="hosting" data-v-d4fad165><h2 data-v-d4fad165>Running locally &amp; on a server</h2><h3 data-v-d4fad165>Local setup</h3><ol data-v-d4fad165><li data-v-d4fad165>Install Python deps: <code data-v-d4fad165>pip install -e .</code></li><li data-v-d4fad165>Install and build frontend: <code data-v-d4fad165>cd frontend &amp;&amp; npm install &amp;&amp; npm run build</code></li><li data-v-d4fad165>Start the server: <code data-v-d4fad165>python -m cspm.cli ui --host 127.0.0.1 --port 8000</code></li><li data-v-d4fad165>Open <code data-v-d4fad165>http://127.0.0.1:8000</code>, select your cloud, and enter credentials in Setup.</li></ol><h3 data-v-d4fad165>Hosted on a server</h3><ol data-v-d4fad165><li data-v-d4fad165>Build the frontend on the server (or copy the <code data-v-d4fad165>frontend/dist/</code> build).</li><li data-v-d4fad165>Run: <code data-v-d4fad165>python -m cspm.cli ui --host 0.0.0.0 --port 8000</code></li><li data-v-d4fad165>Put Nginx or another reverse proxy in front with HTTPS.</li><li data-v-d4fad165> Add this to your Nginx location block for <code data-v-d4fad165>/api/jobs/</code> and <code data-v-d4fad165>/api/tests/</code> to prevent SSE buffering: <pre class="doc-code" data-v-d4fad165>proxy_buffering off;
X-Accel-Buffering: no;</pre></li><li data-v-d4fad165>Prefer IAM roles (AWS), workload identity (GCP), or managed identity (Azure) instead of storing plain-text keys in <code data-v-d4fad165>config.yaml</code>.</li></ol><h3 data-v-d4fad165>Docker</h3><p data-v-d4fad165>A <code data-v-d4fad165>docker-compose.yml</code> is included. Run <code data-v-d4fad165>docker compose up --build</code> to start the full stack. Set credentials via environment variables or mount a <code data-v-d4fad165>config.yaml</code> volume.</p></section>`,14)])])}const f=a(s,[["render",n],["__scopeId","data-v-d4fad165"]]);export{f as default};
